import type { KitsResponsiveValue } from '@lmb-it/kitsconcerto-types';

const BREAKPOINT_KEYS = ['base', 'xs', 'sm', 'md', 'lg', 'xl', 'xxl', 'xxxl'] as const;

const isPrimitive = (v: unknown): v is string | number =>
    typeof v === 'string' || typeof v === 'number';

/**
 * Normalises a scalar / array / object responsive value into a
 * breakpoint-keyed record: `{ base: '100%', md: '50%' }`.
 */
export const expandResponsiveValue = <T>(
    value: KitsResponsiveValue<T>,
): Record<string, T> => {
  const out: Record<string, T> = {};

  if (value == null) return out;

  if (isPrimitive(value)) {
    out.base = value as T;
    return out;
  }

  if (Array.isArray(value)) {
    value.forEach((v, i) => {
      if (v !== undefined && i < BREAKPOINT_KEYS.length) {
        // @ts-ignore
        out[BREAKPOINT_KEYS[i]] = v as T;
      }
    });
    return out;
  }

  // Object form — may contain nested responsive objects (e.g. `{ md: { lg: '50%' } }`)
  Object.entries(value as Record<string, unknown>).forEach(([k, v]) => {
    if (v == null) return;

    if (typeof v === 'object' && !Array.isArray(v)) {
      const nested = expandResponsiveValue(v as KitsResponsiveValue<T>);
      Object.entries(nested).forEach(([nk, nv]) => {
        out[`${k}:${nk}`] = nv as T;
      });
    } else {
      out[k] = v as T;
    }
  });

  return out;
};

/**
 * Creates a breakpoint-keyed object from a scalar / array / object value,
 * optionally transforming each value through `transform`.
 */
export const generateResponsiveObject = (
    _property: string,
    values: unknown,
    transform?: (value: unknown) => unknown,
): Record<string, unknown> => {
  const classes: Record<string, unknown> = {};

  if (Array.isArray(values)) {
    values.forEach((item, index) => {
      if (index < BREAKPOINT_KEYS.length) {
        // @ts-ignore
        classes[BREAKPOINT_KEYS[index]] = transform ? transform(item) : item;
      }
    });
  } else if (typeof values === 'object' && values !== null) {
    Object.entries(values).forEach(([k, v]) => {
      classes[k] = transform ? transform(v) : v;
    });
  } else {
    if (values === 0 || values) {
      classes.base = transform ? transform(values) : values;
    }
  }

  return classes;
};
